Searching a sorted inventory array using binary division:

```cpp
#include <vector>

int BinarySearch(const std::vector<int>& SortedArray, int Target) {
    int Low = 0;
    int High = SortedArray.size() - 1;

    while (Low <= High) {
        int Mid = Low + (High - Low) / 2;
        if (SortedArray[Mid] == Target) return Mid;
        if (SortedArray[Mid] < Target) Low = Mid + 1;
        else High = Mid - 1;
    }
    return -1; // Not found
}
```
